jQuery(document).ready(function(){
jQuery("a").creep();
});


jQuery(function() {
  //caches a jQuery object containing the header element
  var header = jQuery(".site-header");
  jQuery(window).scroll(function() {
      var scroll = jQuery(window).scrollTop();

      if (scroll >= 45) {
          header.addClass("tulia");
      } else {
          header.removeClass("tulia").addClass('site-header');
      }
  });
});


jQuery('.menu-link').click( function(){
  jQuery(this).toggleClass('width');
  jQuery(this).parent().toggleClass('show');
  // jQuery(this).children().toggleClass( 'fa-navicon').toggleClass( 'fa-close');
  jQuery('.menu-wrap').toggleClass('nav-show');
  jQuery('.site').toggleClass('Cover');

});

jQuery('.menu-wrap a').click( function(){
  jQuery('.menu-link').removeClass('width');
  // jQuery(this).children().toggleClass( 'fa-navicon').toggleClass( 'fa-close');
  jQuery('.menu-wrap').removeClass('nav-show');
  jQuery('.site').toggleClass('Cover');
  jQuery('.main-navigation').removeClass('show');

});

jQuery('.Layer').click( function(){
  jQuery('.menu-wrap').removeClass('nav-show');
  jQuery('.menu-link').removeClass('width');
  jQuery('.main-navigation').removeClass('show');
  jQuery('.site').toggleClass('Cover');
});





